memberdef.initializer:
    xmlSchemaAnnotPtr cur = item->annot; \
    if (item->annot == NULL) {  \
	item->annot = annot;    \
	return (annot);         \
    }                           \
    cur = item->annot;          \
    while (cur->next != NULL) { \
	cur = cur->next;	\
    }                           \
    cur->next = annot;
